mapper.select:
select distinct u.id, u.username, u.phone, u.password, u.enabled, u.avatar_url, u.created_at from campus_user u inner join campus_user_role ur on ur.user_id = u.id inner join campus_role r on r.id = ur.role_id where r.code = #{roleCode}
and (u.username like concat('%', #{keyword}, '%') or u.phone like concat('%', #{keyword}, '%'))
order by u.id desc
